// Generated by AI (UnitTest MCP)
use std::collections::HashSet;

use sha2::{Digest, Sha256};

use crate::store::ConformanceAudit;
use crate::{
    now_unix, CodeBindingMode, ConformanceCheck, ConformanceEvidence, ConformanceResult, Lodestar,
    LodestarError, Result, Task, TaskStatus, Verdict,
};

const MAX_EVIDENCE_EVENTS: usize = 200;
const MAX_EVIDENCE_PROVENANCE: usize = 1_000;
const MAX_EVIDENCE_SUMMARY_BYTES: usize = 4_096;

impl Lodestar {
    /// Complete a task using one authoritative, claim-bounded conformance check
    /// (ADR-0009). The optional semantic judge is not invoked again here.
    pub fn complete_task(
        &self,
        id: &str,
        agent: &str,
        evidence: &ConformanceEvidence,
        check: &ConformanceCheck,
    ) -> Result<(bool, ConformanceResult)> {
        let now = now_unix();
        let agent = self.resolve_agent(agent)?;
        let task = self
            .store
            .get_task(id)?
            .ok_or_else(|| LodestarError::NotFound(id.to_string()))?;
        self.validate_claim_evidence(&task, agent, evidence, now)?;
        let serialized = serde_json::to_string(evidence)?;
        let record = self
            .store
            .conformance_record(check.id)?
            .ok_or_else(|| LodestarError::NotFound(format!("conformance check {}", check.id)))?;
        let findings = check.findings.join("; ");
        let claim_started_at = task.claim_started_at.unwrap_or(now);
        if record.task_id.as_deref() != Some(id)
            || record.evidence_schema_version != evidence.schema_version
            || record.evidence != serialized
            || record.verdict != check.verdict
            || record.findings != findings
            || record.checked_at < claim_started_at
            || record.checked_at > now
        {
            return Err(LodestarError::Invalid(format!(
                "conformance check {} does not match the live task claim and evidence",
                check.id
            )));
        }
        let expected_token = self.conformance_token(check.id, evidence, check, Some(&task))?;
        if check.token != expected_token {
            return Err(LodestarError::Invalid(format!(
                "conformance check {} is stale; check the evidence again",
                check.id
            )));
        }
        let conformance = ConformanceResult {
            verdict: check.verdict,
            findings: check.findings.clone(),
        };
        let target_status = match conformance.verdict {
            Verdict::Aligned => TaskStatus::Done,
            Verdict::Violation => TaskStatus::Blocked,
            Verdict::Drift | Verdict::NeedsHuman => TaskStatus::InReview,
        };
        if !self.store.transition_with_checked_conformance(
            id,
            agent,
            check.id,
            conformance.verdict,
            target_status,
            now,
        )? {
            return Err(LodestarError::Invalid(format!(
                "task {id} claim changed before conformance could be recorded"
            )));
        }
        Ok((conformance.verdict == Verdict::Aligned, conformance))
    }

    /// Check evidence without changing task state; uses the completion evaluator.
    pub fn check_conformance(
        &self,
        evidence: &ConformanceEvidence,
        task_id: Option<&str>,
    ) -> Result<ConformanceCheck> {
        let resolved_task_id = match (task_id, evidence.task_id.as_deref()) {
            (Some(left), Some(right)) if left != right => {
                return Err(LodestarError::Invalid(
                    "evidence task_id does not match requested task".to_string(),
                ));
            }
            (Some(id), _) | (_, Some(id)) => Some(id),
            (None, None) => None,
        };
        let task = match resolved_task_id {
            Some(id) => Some(
                self.store
                    .get_task(id)?
                    .ok_or_else(|| LodestarError::NotFound(id.to_string()))?,
            ),
            None => None,
        };
        if let Some(task) = task.as_ref() {
            let agent = self.resolve_agent(&evidence.agent_id)?;
            self.validate_claim_evidence(task, agent, evidence, now_unix())?;
        } else {
            self.validate_evidence_shape(evidence)?;
        }
        let conformance = self.evaluate_conformance(evidence, task.as_ref())?;
        let serialized = serde_json::to_string(evidence)?;
        let findings = conformance.findings.join("; ");
        let id = self.store.record_conformance(
            resolved_task_id,
            ConformanceAudit {
                evidence_schema_version: evidence.schema_version,
                evidence: &serialized,
                verdict: conformance.verdict,
                findings: &findings,
            },
            now_unix(),
        )?;
        let mut checked = ConformanceCheck {
            id,
            token: String::new(),
            verdict: conformance.verdict,
            findings: conformance.findings,
        };
        checked.token = self.conformance_token(id, evidence, &checked, task.as_ref())?;
        Ok(checked)
    }

    fn conformance_token(
        &self,
        id: i64,
        evidence: &ConformanceEvidence,
        check: &ConformanceCheck,
        task: Option<&Task>,
    ) -> Result<String> {
        let mut basis = Vec::new();
        if let Some(task) = task {
            basis.push(format!(
                "claim:{}:{}:{}:{}",
                task.id,
                task.goal_id,
                task.owner.as_deref().unwrap_or_default(),
                task.claim_started_at.unwrap_or_default()
            ));
            let goal = self
                .store
                .get_goal(&task.goal_id)?
                .ok_or_else(|| LodestarError::NotFound(task.goal_id.clone()))?;
            basis.push(format!("task-goal:{}", serde_json::to_string(&goal)?));
        }

        let mut nodes = evidence.changed_node_ids.clone();
        nodes.sort();
        nodes.dedup();
        for node in &nodes {
            for binding in self.store.active_bindings_for_node(node)? {
                basis.push(format!(
                    "binding:{node}:{}:{}",
                    binding.mode.as_str(),
                    serde_json::to_string(&binding.goal)?
                ));
            }
        }
        let changed: HashSet<&str> = nodes.iter().map(String::as_str).collect();
        for knowledge in self.store.active_knowledge(now_unix())? {
            if knowledge
                .referenced_nodes()
                .iter()
                .any(|node| changed.contains(node.as_str()))
            {
                basis.push(format!("knowledge:{}", serde_json::to_string(&knowledge)?));
            }
        }
        basis.sort();

        let mut hasher = Sha256::new();
        hasher.update(id.to_le_bytes());
        hasher.update(serde_json::to_vec(evidence)?);
        hasher.update(check.verdict.as_str().as_bytes());
        hasher.update(serde_json::to_vec(&check.findings)?);
        hasher.update(basis.join("\n").as_bytes());
        Ok(hasher
            .finalize()
            .iter()
            .map(|byte| format!("{byte:02x}"))
            .collect())
    }

    /// Score evidence against governing intent, then layer ADR-0022 advisory
    /// knowledge on top. The base pass owns all hard verdicts (Drift / Violation /
    /// NeedsHuman / Aligned from goals and the Constitution); the knowledge pass
    /// may only add advisory findings and, at most, nudge an otherwise-`Aligned`
    /// verdict to `NeedsHuman` — it can never harden a verdict or emit `Violation`.
    fn evaluate_conformance(
        &self,
        evidence: &ConformanceEvidence,
        task: Option<&Task>,
    ) -> Result<ConformanceResult> {
        let mut result = self.evaluate_base_conformance(evidence, task)?;
        self.apply_knowledge_advisory(evidence, &mut result)?;
        Ok(result)
    }

    /// Consult learned knowledge (ADR-0022). When the evidence's changed nodes
    /// intersect the nodes a proven regularity references, attach an ADVISORY
    /// finding and, at most, escalate an `Aligned` verdict to `NeedsHuman` so a
    /// human looks. Knowledge is revalidated and decaying, so it MUST NOT emit a
    /// `Violation` or otherwise harden the verdict — only the Constitution
    /// (constraint / invariant goals) hard-fails. This read path stays
    /// deterministic: no LLM.
    fn apply_knowledge_advisory(
        &self,
        evidence: &ConformanceEvidence,
        result: &mut ConformanceResult,
    ) -> Result<()> {
        if evidence.changed_node_ids.is_empty() {
            return Ok(());
        }
        let changed: HashSet<&str> = evidence
            .changed_node_ids
            .iter()
            .map(String::as_str)
            .collect();
        let mut matched = false;
        for knowledge in self.store.active_knowledge(now_unix())? {
            if knowledge
                .referenced_nodes()
                .iter()
                .any(|node| changed.contains(node.as_str()))
            {
                matched = true;
                result.findings.push(format!(
                    "advisory: learned knowledge {} — {}",
                    knowledge.id, knowledge.statement
                ));
            }
        }
        if matched && result.verdict == Verdict::Aligned {
            result.verdict = Verdict::NeedsHuman;
        }
        Ok(())
    }

    fn evaluate_base_conformance(
        &self,
        evidence: &ConformanceEvidence,
        task: Option<&Task>,
    ) -> Result<ConformanceResult> {
        let mut findings = Vec::new();
        if evidence.changed_node_ids.is_empty() || evidence.provenance.is_empty() {
            findings.push("evidence contains no provenance-bearing mutation".to_string());
            return Ok(ConformanceResult {
                verdict: Verdict::NeedsHuman,
                findings,
            });
        }

        let mut touched_task_goal = false;
        let mut wrong_goals = Vec::new();
        for node in &evidence.changed_node_ids {
            for binding in self.store.active_bindings_for_node(node)? {
                if binding.mode == CodeBindingMode::ForbidChange {
                    findings.push(format!("{} forbids changes to {node}", binding.goal.id));
                    return Ok(ConformanceResult {
                        verdict: Verdict::Violation,
                        findings,
                    });
                }
                match task {
                    Some(task) if binding.goal.id == task.goal_id => touched_task_goal = true,
                    Some(_) => wrong_goals.push(binding.goal.id),
                    None => wrong_goals.push(binding.goal.id),
                }
            }
        }

        if !wrong_goals.is_empty() {
            wrong_goals.sort();
            wrong_goals.dedup();
            findings.push(format!(
                "governed code changed without a covering task: {}",
                wrong_goals.join(", ")
            ));
            return Ok(ConformanceResult {
                verdict: Verdict::Drift,
                findings,
            });
        }

        let Some(task) = task else {
            findings.push("no governed code touched".to_string());
            return Ok(ConformanceResult {
                verdict: Verdict::Aligned,
                findings,
            });
        };
        if !touched_task_goal {
            findings.push("evidence does not touch code bound to the task goal".to_string());
            return Ok(ConformanceResult {
                verdict: Verdict::NeedsHuman,
                findings,
            });
        }

        let goal = self
            .store
            .get_goal(&task.goal_id)?
            .ok_or_else(|| LodestarError::NotFound(task.goal_id.clone()))?;
        if goal.kind.is_normative() {
            match self.judge_conformance(&goal.statement, &evidence.summary) {
                Ok((verdict, rationale)) if verdict == "aligned" => {
                    findings.push(format!("semantic check aligned: {rationale}"));
                }
                Ok((verdict, rationale)) if verdict == "violation" => {
                    findings.push(format!("semantic check found a violation: {rationale}"));
                    return Ok(ConformanceResult {
                        verdict: Verdict::Violation,
                        findings,
                    });
                }
                Ok((_, rationale)) => {
                    findings.push(format!("semantic check needs human review: {rationale}"));
                    return Ok(ConformanceResult {
                        verdict: Verdict::NeedsHuman,
                        findings,
                    });
                }
                Err(_) => {
                    findings.push("semantic check unavailable".to_string());
                    return Ok(ConformanceResult {
                        verdict: Verdict::NeedsHuman,
                        findings,
                    });
                }
            }
        }

        findings.push(format!("evidence covers task goal {}", task.goal_id));
        Ok(ConformanceResult {
            verdict: Verdict::Aligned,
            findings,
        })
    }

    fn validate_evidence_shape(&self, evidence: &ConformanceEvidence) -> Result<()> {
        if evidence.schema_version != 1 {
            return Err(LodestarError::Invalid(format!(
                "unsupported evidence schema version {}",
                evidence.schema_version
            )));
        }
        if evidence.started_at > evidence.ended_at {
            return Err(LodestarError::Invalid(
                "evidence start must not be after its end".to_string(),
            ));
        }
        if evidence.agent_id.trim().is_empty() {
            return Err(LodestarError::Invalid(
                "evidence agent must not be empty".to_string(),
            ));
        }
        if evidence.execution_ids.len() > MAX_EVIDENCE_EVENTS
            || evidence.commit_ids.len() > MAX_EVIDENCE_EVENTS
            || evidence.provenance.len() > MAX_EVIDENCE_PROVENANCE
            || evidence.summary.len() > MAX_EVIDENCE_SUMMARY_BYTES
        {
            return Err(LodestarError::Invalid(
                "evidence exceeds the bounded ADR-0009 contract".to_string(),
            ));
        }
        if !evidence
            .successful_execution_ids
            .iter()
            .all(|id| evidence.execution_ids.contains(id))
        {
            return Err(LodestarError::Invalid(
                "successful executions must be included in execution_ids".to_string(),
            ));
        }
        let agent_node_id = format!("agent:{}", evidence.agent_id);
        for event_id in evidence
            .execution_ids
            .iter()
            .chain(evidence.commit_ids.iter())
        {
            if !evidence.provenance.iter().any(|fact| {
                fact.source_id == agent_node_id
                    && fact.target_id == *event_id
                    && fact.relation == "observed"
            }) {
                return Err(LodestarError::Invalid(format!(
                    "event {event_id} lacks agent observation provenance"
                )));
            }
        }
        for changed_id in &evidence.changed_node_ids {
            if !evidence.provenance.iter().any(|fact| {
                fact.target_id == *changed_id
                    && matches!(fact.relation.as_str(), "modified" | "refactored")
                    && (evidence.execution_ids.contains(&fact.source_id)
                        || evidence.commit_ids.contains(&fact.source_id))
            }) {
                return Err(LodestarError::Invalid(format!(
                    "changed node {changed_id} lacks mutation provenance"
                )));
            }
        }
        for failed_id in &evidence.failed_node_ids {
            if !evidence.provenance.iter().any(|fact| {
                fact.target_id == *failed_id
                    && fact.relation == "failed_on"
                    && evidence.execution_ids.contains(&fact.source_id)
            }) {
                return Err(LodestarError::Invalid(format!(
                    "failed node {failed_id} lacks failure provenance"
                )));
            }
        }
        Ok(())
    }

    fn validate_claim_evidence(
        &self,
        task: &Task,
        agent: &str,
        evidence: &ConformanceEvidence,
        now: i64,
    ) -> Result<()> {
        self.validate_evidence_shape(evidence)?;
        if evidence.task_id.as_deref() != Some(task.id.as_str()) {
            return Err(LodestarError::Invalid(
                "evidence task_id does not identify the claimed task".to_string(),
            ));
        }
        if evidence.agent_id != agent || task.owner.as_deref() != Some(agent) {
            return Err(LodestarError::Invalid(
                "evidence agent does not own the task".to_string(),
            ));
        }
        let lease_expired = match task.lease_expires_at {
            Some(end) => end < now,
            None => true,
        };
        if task.status != TaskStatus::Claimed || lease_expired {
            return Err(LodestarError::Invalid(
                "task does not have a live claim".to_string(),
            ));
        }
        let claim_started_at = task.claim_started_at.ok_or_else(|| {
            LodestarError::Invalid("task claim has no evidence-window start".to_string())
        })?;
        if evidence.started_at < claim_started_at
            || evidence.ended_at > now
            || evidence.ended_at > task.lease_expires_at.unwrap_or(evidence.ended_at)
        {
            return Err(LodestarError::Invalid(
                "evidence interval falls outside the live claim".to_string(),
            ));
        }
        Ok(())
    }

    /// The durable, append-only conformance evidence chain for a task: each
    /// record carries its stable id, the recorded evidence bundle, the verdict,
    /// findings, and when it was checked — the resolvable link proving how (and
    /// whether) the task reached completion.
    pub fn conformance_history(&self, task_id: &str) -> Result<Vec<crate::ConformanceRecord>> {
        self.store.conformance_history(task_id)
    }
}

#[cfg(test)]
mod tests {
    use std::sync::atomic::{AtomicUsize, Ordering};
    use std::sync::Arc;

    use super::*;
    use crate::facade::test_support::engine;
    use crate::{EvidenceProvenance, GoalKind};

    #[test]
    fn completion_uses_the_aligned_preflight_for_identical_evidence() {
        // Bug regression: check_conformance and complete_task used to invoke the
        // optional judge independently, so identical evidence could preflight as
        // aligned and then strand the task in review on a different model answer.
        let judge_calls = Arc::new(AtomicUsize::new(0));
        let calls = Arc::clone(&judge_calls);
        let e = Lodestar::open_in_memory()
            .unwrap()
            .with_test_judge(move |_, _| {
                let verdict = if calls.fetch_add(1, Ordering::SeqCst) == 0 {
                    "aligned"
                } else {
                    "needs_human"
                };
                Ok((verdict.into(), format!("stub returned {verdict}")))
            });
        let goal = e
            .define_goal(
                GoalKind::Constraint,
                "Clean delivery",
                "changes use clean design",
                None,
            )
            .unwrap();
        let node_id = "artifact:src/delivery.rs";
        e.link_goal_to_code(&goal.id, &[node_id.into()], CodeBindingMode::Governed)
            .unwrap();
        let task = e
            .create_task(&goal.id, "fix delivery", "same evidence stays aligned")
            .unwrap();
        e.claim_task(&task.id, "agent-a", 300).unwrap();
        let claimed = e.store.get_task(&task.id).unwrap().unwrap();
        let mut evidence = test_evidence(Some(task.id.clone()), "agent-a", node_id);
        evidence.started_at = claimed.claim_started_at.unwrap();
        evidence.ended_at = now_unix();

        let checked = e.check_conformance(&evidence, Some(&task.id)).unwrap();
        assert_eq!(checked.verdict, Verdict::Aligned);

        let (completed, completion) = e
            .complete_task(&task.id, "agent-a", &evidence, &checked)
            .unwrap();
        assert!(completed);
        assert_eq!(completion.verdict, checked.verdict);
        assert_eq!(completion.findings, checked.findings);
        assert_eq!(
            e.store.get_task(&task.id).unwrap().unwrap().status,
            TaskStatus::Done
        );
        let history = e.conformance_history(&task.id).unwrap();
        assert_eq!(history.len(), 1);
        assert_eq!(history[0].id, checked.id);
        assert_eq!(judge_calls.load(Ordering::SeqCst), 1);
    }

    #[test]
    fn completion_rejects_changed_evidence_or_intent_state() {
        let e = engine();
        let goal = e
            .define_goal(GoalKind::Objective, "Ship search", "add search", None)
            .unwrap();
        let node_id = "artifact:src/search.rs";
        e.link_goal_to_code(&goal.id, &[node_id.into()], CodeBindingMode::Governed)
            .unwrap();
        let task = e.create_task(&goal.id, "wire search", "done").unwrap();
        e.claim_task(&task.id, "agent-a", 300).unwrap();
        let claimed = e.store.get_task(&task.id).unwrap().unwrap();
        let mut evidence = test_evidence(Some(task.id.clone()), "agent-a", node_id);
        evidence.started_at = claimed.claim_started_at.unwrap();
        evidence.ended_at = now_unix();
        let checked = e.check_conformance(&evidence, Some(&task.id)).unwrap();

        let mut changed_evidence = evidence.clone();
        changed_evidence.summary.push_str(" after preflight");
        assert!(e
            .complete_task(&task.id, "agent-a", &changed_evidence, &checked)
            .unwrap_err()
            .to_string()
            .contains("does not match"));

        let other_goal = e
            .define_goal(GoalKind::Objective, "Own search", "separate owner", None)
            .unwrap();
        e.link_goal_to_code(&other_goal.id, &[node_id.into()], CodeBindingMode::Governed)
            .unwrap();
        assert!(e
            .complete_task(&task.id, "agent-a", &evidence, &checked)
            .unwrap_err()
            .to_string()
            .contains("is stale"));
        assert_eq!(
            e.store.get_task(&task.id).unwrap().unwrap().status,
            TaskStatus::Claimed
        );
    }

    #[test]
    fn uncertain_checked_completion_is_reopenable_and_keeps_its_evidence_link() {
        let e = engine();
        let goal = e
            .define_goal(GoalKind::Objective, "Ship auth", "change auth", None)
            .unwrap();
        let task = e.create_task(&goal.id, "change auth", "done").unwrap();
        e.claim_task(&task.id, "agent-a", 300).unwrap();
        let claimed = e.store.get_task(&task.id).unwrap().unwrap();
        let evidence = ConformanceEvidence {
            schema_version: 1,
            task_id: Some(task.id.clone()),
            agent_id: "agent-a".into(),
            started_at: claimed.claim_started_at.unwrap(),
            ended_at: now_unix(),
            changed_node_ids: Vec::new(),
            failed_node_ids: Vec::new(),
            execution_ids: Vec::new(),
            successful_execution_ids: Vec::new(),
            commit_ids: Vec::new(),
            summary: "no mutation evidence".into(),
            provenance: Vec::new(),
        };
        let checked = e.check_conformance(&evidence, Some(&task.id)).unwrap();
        assert_eq!(checked.verdict, Verdict::NeedsHuman);

        let (completed, result) = e
            .complete_task(&task.id, "agent-a", &evidence, &checked)
            .unwrap();
        assert!(!completed);
        assert_eq!(result.verdict, Verdict::NeedsHuman);
        assert!(e.reopen_task(&task.id).unwrap());
        assert_eq!(
            e.store.get_task(&task.id).unwrap().unwrap().status,
            TaskStatus::Open
        );
        let history = e.conformance_history(&task.id).unwrap();
        assert_eq!(history.len(), 1);
        assert_eq!(history[0].id, checked.id);
    }

    #[test]
    fn conformance_flags_ungoverned_as_aligned_and_governed_as_drift() {
        let e = engine();
        let g = e
            .define_goal(
                GoalKind::Constraint,
                "Auth stays typed",
                "no stringly auth",
                None,
            )
            .unwrap();
        e.link_goal_to_code(
            &g.id,
            &["artifact:src/auth.rs".into()],
            CodeBindingMode::Governed,
        )
        .unwrap();

        let free_evidence = test_evidence(None, "agent-a", "artifact:src/unrelated.rs");
        let free = e.check_conformance(&free_evidence, None).unwrap();
        assert_eq!(free.verdict, Verdict::Aligned);

        let drift_evidence = test_evidence(None, "agent-a", "artifact:src/auth.rs");
        let drift = e.check_conformance(&drift_evidence, None).unwrap();
        assert_eq!(drift.verdict, Verdict::Drift);
    }

    #[test]
    fn learned_knowledge_adds_advisory_and_nudges_aligned_to_needs_human() {
        let e = engine();
        // A proven regularity referencing a node (ADR-0022).
        e.consolidate(
            "changes to gizmo break the parser",
            &[
                "artifact:src/gizmo.rs".into(),
                "execution:2".into(),
                "execution:3".into(),
            ],
            0,
            10 * 24 * 3600,
        )
        .unwrap();

        // Ungoverned change would be Aligned on its own, but it touches a node a
        // learned regularity references, so an advisory finding attaches and the
        // verdict is nudged to NeedsHuman — never Violation.
        let evidence = test_evidence(None, "agent-a", "artifact:src/gizmo.rs");
        let res = e.check_conformance(&evidence, None).unwrap();
        assert_eq!(res.verdict, Verdict::NeedsHuman);
        assert_ne!(res.verdict, Verdict::Violation);
        assert!(res
            .findings
            .iter()
            .any(|f| f.contains("advisory: learned knowledge")));
    }

    #[test]
    fn learned_knowledge_never_hardens_a_verdict_or_emits_violation() {
        let e = engine();
        // Governed code so the base verdict is Drift (no covering task).
        let g = e
            .define_goal(
                GoalKind::Constraint,
                "Parser typed",
                "no stringly parser",
                None,
            )
            .unwrap();
        e.link_goal_to_code(
            &g.id,
            &["artifact:src/parser.rs".into()],
            CodeBindingMode::Governed,
        )
        .unwrap();
        // A regularity that also references the changed node.
        e.consolidate(
            "changes to parser break the lexer",
            &[
                "artifact:src/parser.rs".into(),
                "execution:2".into(),
                "execution:3".into(),
            ],
            0,
            10 * 24 * 3600,
        )
        .unwrap();

        let evidence = test_evidence(None, "agent-a", "artifact:src/parser.rs");
        let res = e.check_conformance(&evidence, None).unwrap();
        // Knowledge annotates but never changes a non-Aligned verdict, and can
        // never produce a hard Violation — only the Constitution hard-fails.
        assert_eq!(res.verdict, Verdict::Drift);
        assert!(res
            .findings
            .iter()
            .any(|f| f.contains("advisory: learned knowledge")));
    }

    #[test]
    fn covering_task_without_evidence_needs_human_review() {
        let e = engine();
        let g = e
            .define_goal(GoalKind::Objective, "Auth typed", "harden auth", None)
            .unwrap();
        e.link_goal_to_code(
            &g.id,
            &["artifact:src/auth.rs".into()],
            CodeBindingMode::Governed,
        )
        .unwrap();
        let t = e.create_task(&g.id, "harden auth", "").unwrap();
        e.claim_task(&t.id, "agent-a", 300).unwrap();
        let claimed = e.store.get_task(&t.id).unwrap().unwrap();
        let evidence = ConformanceEvidence {
            schema_version: 1,
            task_id: Some(t.id.clone()),
            agent_id: "agent-a".into(),
            started_at: claimed.claim_started_at.unwrap(),
            ended_at: now_unix(),
            changed_node_ids: Vec::new(),
            failed_node_ids: Vec::new(),
            execution_ids: Vec::new(),
            successful_execution_ids: Vec::new(),
            commit_ids: Vec::new(),
            summary: "no activity".into(),
            provenance: Vec::new(),
        };
        let res = e.check_conformance(&evidence, Some(&t.id)).unwrap();
        assert_eq!(res.verdict, Verdict::NeedsHuman);
    }

    fn test_evidence(
        task_id: Option<String>,
        agent: &str,
        changed_node_id: &str,
    ) -> ConformanceEvidence {
        ConformanceEvidence {
            schema_version: 1,
            task_id,
            agent_id: agent.into(),
            started_at: 1,
            ended_at: 2,
            changed_node_ids: vec![changed_node_id.into()],
            failed_node_ids: Vec::new(),
            execution_ids: vec!["execution:proof".into()],
            successful_execution_ids: vec!["execution:proof".into()],
            commit_ids: Vec::new(),
            summary: format!("changed {changed_node_id}"),
            provenance: vec![
                EvidenceProvenance {
                    source_id: format!("agent:{agent}"),
                    target_id: "execution:proof".into(),
                    relation: "observed".into(),
                },
                EvidenceProvenance {
                    source_id: "execution:proof".into(),
                    target_id: changed_node_id.into(),
                    relation: "modified".into(),
                },
            ],
        }
    }
}
